import React, { useState } from 'react';
import { Users, CheckCircle, Clock, AlertTriangle, TrendingUp, Calendar, ChevronDown } from 'lucide-react';
import Sidebar from './Sidebar';
import MonthCalendar from './MonthCalendar';
import Schedule from './Schedule';
import { usersData } from '../data/usersData';

const SchedulePage = () => {
  const [selectedUser, setSelectedUser] = useState(null);
  const [selectedDate, setSelectedDate] = useState(new Date());

  // Dados mockados para os widgets
  const weekStats = {
    productivity: 87,
    tasksCreated: 24,
    tasksCompleted: 18,
    tasksPending: 6,
    overdueTasks: 3
  };

  // Função para obter status dos membros da equipe
  const getTeamStatus = () => {
    const statusCounts = usersData.reduce((acc, user) => {
      const status = user.availability || 'Available';
      acc[status] = (acc[status] || 0) + 1;
      return acc;
    }, {});

    return statusCounts;
  };

  const teamStatus = getTeamStatus();

  // Função para gerar schedule personalizado baseado no usuário selecionado
  const generateUserSchedule = (user) => {
    if (!user) return [];

    const scheduleTemplates = [
      {
        day: '02',
        dayName: 'Monday',
        events: [
          {
            id: 1,
            title: `${user.skills && user.skills[0] ? user.skills[0] : 'Project'} Review`,
            time: '2:00pm - 3:30pm',
            isCurrent: false
          },
          {
            id: 2,
            title: 'Team Meeting',
            time: '4:00pm - 5:00pm',
            avatar: user.avatar,
            additionalPeople: '+3',
            isCurrent: true
          }
        ]
      },
      {
        day: '03',
        dayName: 'Tuesday',
        events: [
          {
            id: 3,
            title: 'Daily Standup',
            time: '9:00am - 9:30am',
            isCurrent: false
          },
          {
            id: 4,
            title: `${user.skills && user.skills.length > 0 ? (user.skills[1] || user.skills[0]) : 'General'} Workshop`,
            time: '10:00am - 12:00pm',
            avatar: user.avatar,
            additionalPeople: '+6',
            isCurrent: false
          }
        ]
      }
    ];

    return scheduleTemplates;
  };

  const handleUserSelect = (user) => {
    setSelectedUser(user);
  };

  const handleDateSelect = (date) => {
    setSelectedDate(date);
  };

  return (
    <div className="flex h-screen bg-neutral-900">
      <Sidebar currentPage="schedule" onNavigate={onNavigate} />

      <div className="flex-1 flex">
        {/* Conteúdo Principal */}
        <div className="flex-1 p-6 overflow-y-auto">
          {/* Widgets da Semana */}
          <div className="grid grid-cols-4 gap-6 mb-6">
            {/* Widget 1: Produtividade da Equipe */}
            <div className="bg-neutral-800 border border-neutral-700 rounded-lg p-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="w-10 h-10 bg-green-500/10 rounded-lg flex items-center justify-center">
                  <TrendingUp className="w-5 h-5 text-green-400" />
                </div>
                <div>
                  <h3 className="text-white font-medium">Produtividade</h3>
                  <p className="text-neutral-400 text-sm">Esta semana</p>
                </div>
              </div>
              <div className="flex items-end gap-2">
                <span className="text-2xl font-bold text-white">{weekStats.productivity}%</span>
                <span className="text-green-400 text-sm">+5%</span>
              </div>
            </div>

            {/* Widget 2: Resumo da Semana */}
            <div className="bg-neutral-800 border border-neutral-700 rounded-lg p-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="w-10 h-10 bg-blue-500/10 rounded-lg flex items-center justify-center">
                  <CheckCircle className="w-5 h-5 text-blue-400" />
                </div>
                <div>
                  <h3 className="text-white font-medium">Tarefas</h3>
                  <p className="text-neutral-400 text-sm">Esta semana</p>
                </div>
              </div>
              <div className="space-y-1">
                <div className="flex justify-between text-sm">
                  <span className="text-neutral-400">Criadas:</span>
                  <span className="text-white">{weekStats.tasksCreated}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-neutral-400">Concluídas:</span>
                  <span className="text-green-400">{weekStats.tasksCompleted}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-neutral-400">Pendentes:</span>
                  <span className="text-yellow-400">{weekStats.tasksPending}</span>
                </div>
              </div>
            </div>

            {/* Widget 3: Status dos Membros */}
            <div className="bg-neutral-800 border border-neutral-700 rounded-lg p-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="w-10 h-10 bg-purple-500/10 rounded-lg flex items-center justify-center">
                  <Users className="w-5 h-5 text-purple-400" />
                </div>
                <div>
                  <h3 className="text-white font-medium">Status da Equipe</h3>
                  <p className="text-neutral-400 text-sm">Agora</p>
                </div>
              </div>
              <div className="space-y-1">
                {Object.entries(teamStatus).slice(0, 3).map(([status, count]) => (
                  <div key={status} className="flex justify-between text-sm">
                    <span className="text-neutral-400">{status}:</span>
                    <span className="text-white">{count}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Widget 4: Tarefas Atrasadas */}
            <div className="bg-neutral-800 border border-neutral-700 rounded-lg p-4">
              <div className="flex items-center gap-3 mb-3">
                <div className="w-10 h-10 bg-red-500/10 rounded-lg flex items-center justify-center">
                  <AlertTriangle className="w-5 h-5 text-red-400" />
                </div>
                <div>
                  <h3 className="text-white font-medium">Atrasadas</h3>
                  <p className="text-neutral-400 text-sm">Tarefas</p>
                </div>
              </div>
              <div className="flex items-end gap-2">
                <span className="text-2xl font-bold text-red-400">{weekStats.overdueTasks}</span>
                <span className="text-neutral-400 text-sm">tarefas</span>
              </div>
            </div>
          </div>

          {/* Tabela de Membros da Equipe */}
          <div className="bg-neutral-800 border border-neutral-700 rounded-lg overflow-hidden">
            <div className="px-6 py-4 border-b border-neutral-700">
              <h2 className="text-white text-xl font-semibold">Membros da Equipe</h2>
            </div>

            {/* Cabeçalho da Tabela */}
            <div className="px-6 py-3 text-neutral-400 text-sm font-medium">
              <div className="grid grid-cols-5 gap-4">
                <div>Membro</div>
                <div>Cargo</div>
                <div>Status</div>
                <div>Departamento</div>
                <div>Ações</div>
              </div>
            </div>

            {/* Linhas da Tabela */}
            <div className="divide-y divide-neutral-700">
              {usersData.map((user) => (
                <div
                  key={user.id}
                  className="px-6 py-4 hover:bg-neutral-700/50 transition-colors cursor-pointer"
                  onClick={() => handleUserSelect(user)}
                >
                  <div className="grid grid-cols-5 gap-4 items-center">
                    {/* Avatar e Nome */}
                    <div className="flex items-center gap-3">
                      <img
                        src={user.avatar}
                        alt={user.name}
                        className="w-10 h-10 rounded-full object-cover"
                      />
                      <div>
                        <div className="text-white font-medium">{user.name}</div>
                        <div className="text-neutral-400 text-sm">{user.email}</div>
                      </div>
                    </div>

                    {/* Cargo */}
                    <div className="text-neutral-300">{user.title}</div>

                    {/* Status */}
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${
                        user.status === 'online' ? 'bg-green-400' :
                        user.status === 'away' ? 'bg-yellow-400' : 'bg-gray-400'
                      }`}></div>
                      <span className="text-neutral-300 text-sm">{user.availability}</span>
                    </div>

                    {/* Departamento */}
                    <div className="text-neutral-300">{user.department}</div>

                    {/* Ações */}
                    <div>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleUserSelect(user);
                        }}
                        className="text-blue-400 hover:text-blue-300 text-sm font-medium"
                      >
                        Ver Schedule
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Coluna Direita */}
        <div className="w-80 p-6 border-l border-neutral-700 space-y-6">
          {/* Calendário */}
          <MonthCalendar 
            selectedDate={selectedDate}
            onDateSelect={handleDateSelect}
          />

          {/* Schedule */}
          <div className="flex-1">
            {selectedUser ? (
              <div className="border border-neutral-700 rounded-lg h-full flex flex-col">
                {/* Header do Schedule */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-neutral-700">
                  <div className="flex items-center gap-3">
                    <img
                      src={selectedUser.avatar}
                      alt={selectedUser.name}
                      className="w-8 h-8 rounded-full object-cover"
                    />
                    <div>
                      <h3 className="text-white font-medium">{selectedUser.name}</h3>
                      <p className="text-neutral-400 text-sm">{selectedUser.title}</p>
                    </div>
                  </div>
                  <button
                    onClick={() => setSelectedUser(null)}
                    className="text-neutral-400 hover:text-white text-sm"
                  >
                    ✕
                  </button>
                </div>

                {/* Conteúdo do Schedule */}
                <div className="flex-1 overflow-y-auto px-6 pb-6">
                  <div className="space-y-1">
                    {generateUserSchedule(selectedUser).map((dayData) => (
                      <div key={dayData.day} className="flex gap-4 py-4 border-b border-neutral-700">
                        {/* Day Column */}
                        <div className="flex flex-col items-center w-[40px]">
                          <div className="text-white text-xl font-semibold">{dayData.day}</div>
                          <div className="text-neutral-400 text-xs">{dayData.dayName}</div>
                        </div>

                        {/* Events Column */}
                        <div className="flex-1 space-y-3">
                          {dayData.events.map((event) => (
                            <div
                              key={event.id}
                              className={`rounded-lg p-3 ${
                                event.isCurrent
                                  ? 'bg-cyan-600'
                                  : 'border border-neutral-700 bg-transparent'
                              }`}
                            >
                              <div className="flex items-center justify-between">
                                <div className="flex-1">
                                  <div className={`text-sm font-medium ${
                                    event.isCurrent ? 'text-cyan-200' : 'text-neutral-500'
                                  }`}>
                                    {event.title}
                                  </div>
                                  <div className="text-white text-xs">{event.time}</div>
                                </div>
                                <div className="flex items-center gap-2">
                                  {event.avatar && (
                                    <img 
                                      src={event.avatar} 
                                      alt="Avatar" 
                                      className="w-6 h-6 rounded-full object-cover"
                                    />
                                  )}
                                  {event.additionalPeople && (
                                    <span className={`text-sm ${
                                      event.isCurrent ? 'text-cyan-200' : 'text-neutral-500'
                                    }`}>
                                      {event.additionalPeople}
                                    </span>
                                  )}
                                </div>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              /* Estado Vazio */
              <div className="border border-neutral-700 rounded-lg h-full flex flex-col items-center justify-center p-6">
                <div className="w-16 h-16 bg-neutral-700 rounded-full flex items-center justify-center mb-4">
                  <Calendar className="w-8 h-8 text-neutral-400" />
                </div>
                <h3 className="text-white font-medium mb-2">Selecione um Membro</h3>
                <p className="text-neutral-400 text-sm text-center">
                  Clique em um membro da equipe na tabela para ver seu schedule
                </p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SchedulePage;
